const item = $input.first().json;
const raw = item.text || item.output || '';

// Remove cercas ```json ... ```
let cleaned = String(raw).trim()
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/\s*```$/i, '')
  .trim();

// Tenta isolar o JSON
const match = cleaned.match(/\{[\s\S]*\}/);
let jsonStr = match ? match[0] : cleaned;

// Sanitiza nulls textuais
jsonStr = jsonStr.replace(/"(null|undefined|nulo|nenhum)"/gi, 'null');

try {
  const parsed = JSON.parse(jsonStr);

  const sanitize = (val) => {
    if (val === null || val === undefined) return null;
    const s = String(val).trim().toLowerCase();
    return (s === '' || s === 'null' || s === 'undefined' || s === 'nulo' || s === 'nenhum')
      ? null
      : String(val).trim();
  };

  const dados = parsed.dados || {};
  const dadosLimpos = {
    paciente_nome: sanitize(dados.paciente_nome),
    data_nascimento: sanitize(dados.data_nascimento),
    celular: sanitize(dados.celular),
    convenio: sanitize(dados.convenio),
    medico_nome: sanitize(dados.medico_nome),
    atendimento_nome: sanitize(dados.atendimento_nome),
    data_consulta: sanitize(dados.data_consulta),
    periodo_preferido: sanitize(dados.periodo_preferido)
  };

  if (dadosLimpos.convenio) {
    let c = dadosLimpos.convenio.toUpperCase().trim();

    if (c.includes('HGU')) {
      c = 'HGU';
    } else if (c.includes('UNIMED')) {
      if (c.includes('REGIONAL')) c = 'UNIMED REGIONAL';
      else if (c.includes('NACIONAL')) c = 'UNIMED NACIONAL';
      else if (c.includes('INTERCAMBIO') || c.includes('INTERCÂMBIO')) c = 'UNIMED INTERCAMBIO';
      else if (c.includes('40')) c = 'UNIMED 40%';
      else if (c.includes('20')) c = 'UNIMED 20%';
      else if (c.includes('VSF') || c.includes('VALE DO SÃO') || c.includes('VALE DO SAO')) c = 'UNIMED VSF';
      else c = 'UNIMED';
    }

    dadosLimpos.convenio = c;
  }

  const obrigatorios = [
    'paciente_nome',
    'data_nascimento',
    'celular',
    'convenio',
    'medico_nome',
    'atendimento_nome',
    'data_consulta'
  ];

  const camposFaltando = obrigatorios.filter((c) => !dadosLimpos[c]);

  let intencao = sanitize(parsed.intencao) || 'duvida';
  const confirmacao = parsed.confirmacao_paciente === true;

  let prontoParaAcao = parsed.pronto_para_acao === true;

  if (intencao === 'agendar' && (camposFaltando.length > 0 || !confirmacao)) {
    prontoParaAcao = false;
  }

  let buscaConhecimento = sanitize(parsed.busca_conhecimento);
  const respostaSocial = parsed.resposta_social || '';

  // ═══════════════════════════════════════════════════════════════
  // REDE DE SEGURANÇA — Reclassificação de intenção quando a LLM
  // classificou incorretamente. Regras genéricas (multi-tenant safe).
  // ═══════════════════════════════════════════════════════════════

  // --- NOVA REGRA: Anti-saudação falsa ---
  if (intencao === 'saudacao') {
    const mensagemOriginal = (
      item.mensagem_teste ||
      item.pergunta ||
      item.mensagem_final ||
      ''
    ).toLowerCase().trim();

    const verbosAcao = /\b(marcar|agendar|cancelar|remarcar|saber|consultar|fazer|pedir|precisar|querer|quero|preciso|gostaria|desejo|necessito|perguntar|verificar|confirmar|reagendar)\b/i;
    const substantivosServico = /\b(consulta|exame|teste|mapa|mrpa|ecg|eletro|ergom[eé]tric|receita|retorno|encaixe|agendamento|cancelamento|remarca[çc][aã]o|parecer|checkup|check-up|peri[oó]dico|cateteri|cirurgia|marcapasso)\b/i;
    const mencaoConvenio = /\b(conv[eê]nio|plano|unimed|hgu|bradesco|sulam[eé]rica|cassi|medclin|medprev|sedilab|particular)\b/i;
    const mencaoValor = /\b(valor|pre[çc]o|quanto|custa|cobr|desconto|pagamento|pix|cart[aã]o)\b/i;

    if (mensagemOriginal && (
      verbosAcao.test(mensagemOriginal) ||
      substantivosServico.test(mensagemOriginal) ||
      mencaoConvenio.test(mensagemOriginal) ||
      mencaoValor.test(mensagemOriginal)
    )) {
      const querAgendar = /\b(marcar|agendar|quero|preciso|gostaria|desejo)\b/i.test(mensagemOriginal) &&
                          /\b(consulta|exame|teste|mapa|mrpa|ecg|retorno|peri[oó]dico)\b/i.test(mensagemOriginal);

      const querCancelar = /\b(cancelar|cancelamento|desmarcar)\b/i.test(mensagemOriginal);
      const querRemarcar = /\b(remarcar|reagendar|mudar|alterar)\b/i.test(mensagemOriginal) &&
                           /\b(data|hor[aá]rio|dia|consulta|exame)\b/i.test(mensagemOriginal);
      const querEncaixe = /\b(encaixe|encaixar|emerg[eê]ncia.*passou|alta.*hospital|j[aá].*fui.*emerg)\b/i.test(mensagemOriginal);

      if (querCancelar) {
        intencao = 'cancelar';
      } else if (querRemarcar) {
        intencao = 'remarcar';
      } else if (querEncaixe) {
        intencao = 'encaixe';
      } else if (querAgendar && dadosLimpos.medico_nome) {
        intencao = 'agendar';
      } else {
        intencao = 'duvida';
        if (!buscaConhecimento) {
          buscaConhecimento = mensagemOriginal;
        }
      }
    }
  }

  // --- NOVA REGRA: Agendar sem médico → duvida ---
  if (intencao === 'agendar' && !dadosLimpos.medico_nome) {
    intencao = 'duvida';
    if (!buscaConhecimento) {
      buscaConhecimento = null;
    }
  }

  // ═══════════════════════════════════════════════════════════════
  // REDE DE SEGURANÇA — Força busca_conhecimento quando a LLM
  // não preencheu mas o contexto exige consulta à RAG.
  // ═══════════════════════════════════════════════════════════════

  if (!buscaConhecimento && respostaSocial) {
    const padraoNegacao = /não\s+(realizamos|fazemos|faz|realiza|atendemos|oferecemos|temos)/i;

    if (padraoNegacao.test(respostaSocial)) {
      const mensagem =
        item.mensagem_teste ||
        item.pergunta ||
        item.mensagem_final ||
        '';

      buscaConhecimento = mensagem
        ? 'indicação ' + mensagem + ' onde fazer encaminhar'
        : null;
    }
  }

  if (!buscaConhecimento && dadosLimpos.convenio) {
    buscaConhecimento = 'convênio ' + dadosLimpos.convenio + ' atendido aceito regras';
  }

  if (!buscaConhecimento && /R\$\s?\d/.test(respostaSocial)) {
    const mensagem =
      item.mensagem_teste ||
      item.pergunta ||
      item.mensagem_final ||
      '';

    buscaConhecimento = mensagem || 'valores preços consulta exame';
  }

  // ═══════════════════════════════════════════════════════════════
  // ALTERAÇÃO 4: Extrair estado da conversa e dados_faltantes
  // ═══════════════════════════════════════════════════════════════
  // Validação: só aceita estados permitidos pela constraint do banco
  const ESTADOS_VALIDOS = [
    'novo', 'triagem', 'coletando_dados',
    'aguardando_escolha_medico', 'aguardando_escolha_servico',
    'aguardando_confirmacao', 'aguardando_humano',
    'agendado', 'cancelado', 'encerrado',
    'cancelando_consulta', 'remarcando_consulta',
    'verificando_disponibilidade', 'aguardando_dados_paciente',
    'aguardando_convênio', 'duvida', 'social'
  ];
  const estadoRaw = sanitize(parsed.estado_proximo) || 'triagem';
  const estadoProximo = ESTADOS_VALIDOS.includes(estadoRaw) ? estadoRaw : 'triagem';
  const dadosFaltantes = parsed.dados_faltantes || camposFaltando;

  return [{
    json: {
      intencao,
      pronto_para_acao: prontoParaAcao,
      dados: dadosLimpos,
      campos_faltando: camposFaltando,
      confirmacao_paciente: confirmacao,
      busca_conhecimento: buscaConhecimento,
      resposta_social: respostaSocial || 'Desculpe, pode repetir?',
      parse_ok: true,
      // Alteração 4: novos campos de estado
      estado_proximo: estadoProximo,
      dados_faltantes: dadosFaltantes,
      estado_anterior: $('buscarContextoSessao').first().json.estado_atual || 'novo'
    }
  }];

} catch (e) {
  return [{
    json: {
      intencao: 'duvida',
      pronto_para_acao: false,
      dados: {},
      campos_faltando: [],
      confirmacao_paciente: false,
      busca_conhecimento: null,
      resposta_social: 'Desculpe, pode repetir?',
      parse_ok: false,
      parse_error: String(e.message || e)
    }
  }];
}

let busca = $('parsearRespostaLLM').first().json.busca_conhecimento
  || $('receberDadosWorkflowPai').first().json.mensagem_final
  || '';

// Remove emojis e limita tamanho para evitar problemas na API
busca = busca.replace(/[\u{1F600}-\u{1F9FF}\u{2600}-\u{27BF}\u{1F300}-\u{1F5FF}\u{1F680}-\u{1F6FF}]/gu, '').trim();
busca = busca.substring(0, 500);

const clinicaId = $('receberDadosWorkflowPai').first().json.clinica_id;
return { json: { busca, clinicaId } };

const resultados = $('executarBuscaHibridaRAG').all();
const mensagem = $('receberDadosWorkflowPai').first().json.mensagem_final;

// 1. Memória de Sessão via SQL (Buscar Contexto)
const dadosSessao = $('buscarContextoSessao').first().json;
const resumoSessao = dadosSessao.resumo_contexto || "";
const nomePaciente = dadosSessao.nome_paciente_detectado || "";

// 2. Configurações dinâmicas da clínica (multi-tenant)
const config = $('buscarConfigClinica').first().json;
const nomeClinica = config.nome_clinica || "nossa clínica";
const modeloIA = config.modelo_ia || "google/gemini-2.5-flash";
const promptSistema = config.prompt_sistema || "";

// 3. Monta o bloco de contexto RAG
let contexto = "";
for (const item of resultados) {
  if (item.json.conteudo) {
    contexto += `[${item.json.categoria}] ${item.json.conteudo}\n\n`;
  }
}

// 4. Fallback se o RAG não trouxer nada
if (!contexto.trim()) {
  const respostaSocial = $('parsearRespostaLLM').first().json.resposta_social || "Como posso te ajudar?";
  return { json: { resposta_final: respostaSocial, usou_rag: false } };
}

// 5. Bloco de memória
const blocoMemoria = resumoSessao
  ? `RESUMO DA CONVERSA ATÉ AGORA (use para resolver pronomes como "ele", "esse médico", "esse plano"):
${nomePaciente ? `Paciente: ${nomePaciente}\n` : ""}${resumoSessao}\n\n`
  : "";

// 6. Percepção temporal
const timezone = config.timezone || 'America/Sao_Paulo';
const dataHora = new Date().toLocaleString('pt-BR', { timeZone: timezone, day: '2-digit', month: '2-digit', year: 'numeric', hour: '2-digit', minute: '2-digit' });

// 7. Monta o payload para o OpenRouter
const payload = {
  model: modeloIA,
  messages: [
    {
      role: "system",
      content: `${promptSistema}

REGRA ZERO — PROIBIDO ENROLAR (PRIORIDADE MÁXIMA):
- O contexto abaixo JÁ CONTÉM todas as informações necessárias para responder. USE-AS DIRETAMENTE.
- PROIBIDO dizer "preciso consultar", "vou verificar", "preciso checar", "deixa eu olhar", "vou consultar nossa base" ou qualquer variação. Essas frases são ERRO GRAVE.
- Se a informação está no contexto, RESPONDA DIRETAMENTE. Não peça permissão ao paciente para consultar.
- Se a informação NÃO está no contexto, diga com naturalidade que não tem essa informação e ofereça alternativa.

REGRAS DE OURO DE FORMATAÇÃO (ESTRITAMENTE PROIBIDO VIOLAR):
1. PROIBIDO o uso de asteriscos (*), negritos (**) ou qualquer símbolo Markdown.
2. NUNCA use hifens (-) para listas. Use apenas números (1. , 2. ) ou parágrafos simples.
3. RESPONDA APENAS COM TEXTO PURO.
4. Use apenas UMA quebra de linha (\\n) para separar informações do mesmo assunto. Use DUAS (\\n\\n) apenas quando mudar totalmente de tema. Isso evita excesso de balões no WhatsApp.

REGRAS DE AGENDAMENTO (MUITO IMPORTANTE):
- Você PODE e DEVE oferecer agendamento diretamente pelo chat para qualquer serviço que conste no contexto abaixo.
- NUNCA direcione o paciente para ligar quando o serviço está disponível no banco. Diga que pode agendar por aqui mesmo.
- Se o paciente perguntar sobre um serviço ou procedimento e ele ESTIVER no contexto, confirme que realizamos e ofereça o agendamento pelo chat.
- Se o paciente perguntar sobre algo que NÃO consta no contexto, informe com gentileza que esse serviço não é realizado e, se possível, sugira uma alternativa que esteja disponível.
- NUNCA oriente o paciente a ligar para a clínica como solução padrão. O atendimento acontece aqui, pelo chat.

REGRAS DE FIDELIDADE AO CONTEXTO DA CLÍNICA (CRÍTICO):
- O contexto abaixo é a ÚNICA fonte de verdade sobre esta unidade. Não invente, não suponha, não complete com conhecimento geral.
- Se o contexto disser que NÃO atende SUS, diga isso com clareza e sem rodeios: "Esta unidade NÃO atende pelo SUS."
- Se o contexto mencionar exigências de preparo (ex: dilatação de pupila, jejum, acompanhante), informe o paciente ANTES de confirmar o agendamento.
- Se o contexto contiver uma restrição (ex: não aceita determinado plano, não realiza certo procedimento), trate isso como regra absoluta. NUNCA sugira que "talvez seja possível" ou que o paciente ligue para confirmar.
- Cada clínica tem suas próprias regras. O que vale é SOMENTE o que está no contexto desta conversa.

REGRAS DE VALORES E DADOS EXATOS (CRÍTICO):
- Quando o contexto contiver um VALOR EXATO de coparticipação (ex: "PAGA EXATAMENTE R$ 52,00"), INFORME esse valor diretamente ao paciente.
- NUNCA diga "depende do plano", "varia conforme o contrato" ou "consulte seu convênio" quando o valor já está explícito no contexto.
- Se o paciente perguntar "quanto pago pela UNIMED 40%?" e o contexto diz "R$ 52,00", responda: "Pela UNIMED 40%, o valor é R$ 52,00."
- Se o contexto contiver um HORÁRIO EXATO (ex: "Segunda-feira: 08:00"), INFORME esse horário. Não diga "preciso verificar".
- Se o contexto disser "NÃO tem consulta na quarta de manhã", responda DIRETAMENTE: "Na quarta-feira só temos consulta à TARDE."
- Valores, horários e regras que estão no contexto são DADOS CONFIRMADOS. Use-os com confiança.

REGRAS DE INDICAÇÕES EXTERNAS (IMPORTANTE):
- Quando informar que NÃO realizamos um exame ou procedimento, SEMPRE indique onde o paciente pode fazer.
- Quando informar que NÃO realizamos um exame ou procedimento, SEMPRE verifique no contexto se há indicação de onde o paciente pode fazer. Se houver, informe o local e o profissional indicado. NUNCA diga apenas "não fazemos" sem oferecer alternativa quando ela existir no contexto.
- NUNCA diga apenas "não fazemos" sem oferecer alternativa quando ela está disponível no contexto.

REGRAS DE CONTEÚDO E COMPORTAMENTO:
- NÃO repita saudações (Olá, Bom dia), pois o sistema já iniciou a conversa. Comece confirmando a dúvida ou respondendo a pergunta de forma gentil.
- Se o paciente perguntar "Só atendem [PLANO]?", responda primeiro a dúvida antes de listar os dados técnicos.
- Se a resposta envolver valores, use sempre o formato R$.
- DIFERENCIAL: Use LETRAS MAIÚSCULAS para dar ênfase em pontos importantes, mantendo a naturalidade.
- NUNCA comece com "Entendi", "Certo", "Compreendi" ou "Perfeito".

TRAVA DE CONVERSÃO — REGRA ABSOLUTA DE ENCERRAMENTO:
- TODA resposta DEVE terminar com UMA pergunta curta e direta que mantenha a conversa viva. Isso é OBRIGATÓRIO, sem exceção.
- Se o assunto permite agendamento: "Posso verificar um horário para você?" ou "Quer que eu já separe uma data?"
- Se o paciente recebeu uma informação negativa (serviço não disponível, plano não aceito): ofereça uma alternativa real do contexto e pergunte se quer seguir por esse caminho.
- Se a dúvida foi totalmente resolvida e não há abertura óbvia: use uma pergunta ampla como "Posso te ajudar com mais alguma coisa?"
- PROIBIDO encerrar com frases como "Qualquer dúvida estou aqui.", "Fico à disposição." ou similares — essas frases matam a conversa.
- A pergunta final deve ter NO MÁXIMO uma linha. Sem introdução, sem explicação. Só a pergunta.
- Se a resposta NÃO terminar com "?", ela está INCORRETA. Revise antes de enviar.

DATA E HORA ATUAL: ${dataHora}. Use para validar pedidos de agendamento contra regras de horário do contexto.

${blocoMemoria}CONTEXTO TÉCNICO PARA CONSULTA (regras e informações exclusivas desta unidade):
${contexto}`
    },
    {
      role: "user",
      content: mensagem
    }
  ]
};

return { json: { api_body: payload, usou_rag: true } };

const inputItems = $input.all();
const triggerItems = $('receberDadosWorkflowPai').all();
const results = [];

const perguntasFallback = [
  "\n\nPosso te ajudar com mais alguma informação?",
  "\n\nPosso te ajudar com mais alguma coisa?",
  "\n\nTem mais alguma dúvida?"
];

inputItems.forEach((item, index) => {
    const triggerData = triggerItems[index] ? triggerItems[index].json : triggerItems[0].json;
    const telefone = triggerData.telefone;
    const clinicaId = triggerData.clinica_id;

    const data = item.json;
    let resposta = "";

    if (data.choices && data.choices.length > 0 && data.choices[0].message) {
      resposta = data.choices[0].message.content;
    } else if (data.resposta_final) {
      resposta = data.resposta_final;
    } else {
      resposta = "Desculpe, estou com uma pequena instabilidade. Poderia repetir sua pergunta?";
    }

    // Garante pergunta final se não terminar com "?"
    const respostaTrimmed = resposta.trim();
    const semEmoji = respostaTrimmed
      .replace(/[\u{1F300}-\u{1FAFF}\u{2600}-\u{27BF}\u{FE00}-\u{FE0F}\u{1F900}-\u{1F9FF}\u{200D}\s]+$/u, '')
      .trim();

    if (!semEmoji.endsWith('?')) {
      const idx = Math.floor(Math.random() * perguntasFallback.length);
      resposta = respostaTrimmed + perguntasFallback[idx];
    }

    const partes = resposta.split("\n\n").filter(p => p.trim() !== "");
    partes.forEach(parte => {
        results.push({
            json: {
                texto: parte,
                telefone: telefone,
                clinica_id: clinicaId
            }
        });
    });
});

return results;

// 1. Extraímos os nós FORA do laço de repetição. 
// É ISSO que impede o n8n de entrar em loop infinito e travar.
const prepItems = $('prepararBuscaRAG').all();
const inputItems = $input.all();

// 2. Usamos .map() para processar múltiplos pacientes simultâneos caso cheguem em lote
return inputItems.map((item, index) => {

  // Pareamento seguro: garante que a busca da Clínica A não vá para a Clínica B
  const prepData = prepItems[index] ? prepItems[index].json : prepItems[0].json;

  const busca = prepData.busca;
  const clinicaId = prepData.clinicaId;

  // Pega o embedding do item exato que está sendo processado nesta iteração
  const embedding = item.json.data[0].embedding;
  const embeddingStr = '[' + embedding.join(',') + ']';

  // 3. Dollar-Quoting ($q$ ... $q$) blindando o input do WhatsApp para o Postgres
  const query = `
    SELECT conteudo, categoria, metadata, rrf_score 
    FROM hybrid_search_clinica(
      $q$${busca}$q$,
      '${embeddingStr}'::vector,
      '${clinicaId}',
      6
    );
  `;

  return {
    json: { 
      query: query.trim(), 
      busca: busca 
    }
  };
});

// Puxa os dados universais do Trigger
const triggerData = $('receberDadosWorkflowPai').first().json;
const telefone = triggerData.telefone;
const clinicaId = triggerData.clinica_id;
const results = [];

$input.all().forEach(item => {
    const textoRaw = item.json.texto || item.json.texto_final || item.json.resposta || item.json.output || "Desculpe, ocorreu um erro.";

    // CORREÇÃO: Converte \n literais (string) em quebras de linha reais
    let texto = textoRaw.replace(/\\n/g, '\n');

    // ═══════════════════════════════════════════════════════════════
    // LIMPEZA DE MARKDOWN (a LLM insiste em usar mesmo proibido)
    // ═══════════════════════════════════════════════════════════════
    texto = texto.replace(/\*\*\*(.*?)\*\*\*/g, '$1');  // ***negrito itálico***
    texto = texto.replace(/\*\*(.*?)\*\*/g, '$1');       // **negrito**
    texto = texto.replace(/\*(.*?)\*/g, '$1');            // *itálico*
    texto = texto.replace(/^[\s]*[-•]\s+/gm, '• ');      // Padroniza bullets
    texto = texto.replace(/^[\s]*\*\s+/gm, '• ');        // * usado como bullet
    texto = texto.replace(/#{1,6}\s+/g, '');              // ### headers
    texto = texto.replace(/`{1,3}(.*?)`{1,3}/g, '$1');   // `código`
    texto = texto.replace(/\[([^\]]+)\]\([^)]+\)/g, '$1'); // [link](url) → link

    // FILTRO DE SEGURANÇA (CRÍTICO): Fatia em parágrafos e DESCARTA qualquer parte que comece com JSON '{'
    const partes = texto.split("\n\n").filter(p => p.trim() !== "" && !p.trim().startsWith('{'));

    // Prepara cada fatia purificada para o disparo individual no WhatsApp
    partes.forEach(parte => {
        results.push({
            json: {
                texto_fatiado: parte.trim(),
                telefone: telefone,
                clinica_id: clinicaId
            }
        });
    });
});

return results;

const validacao = $('validarConvenioMedico').first().json.validar_convenio_medico;
const parsedData = $('parsearRespostaLLM').first().json;
const trigger = $('receberDadosWorkflowPai').first().json;

if (validacao.permitido) {
  return [{ json: { ...parsedData, validacao_ok: true } }];
}

// --- PROTEÇÃO CONTRA DADOS INCOMPLETOS ---
// Se o banco deu erro, mas o paciente ainda não informou o dado correspondente,
// ignoramos o erro e usamos a resposta natural da IA (acolhimento).
const medicoVazio = !parsedData.dados.medico_nome || String(parsedData.dados.medico_nome).trim().toLowerCase() === 'null';
const convenioVazio = !parsedData.dados.convenio || String(parsedData.dados.convenio).trim().toLowerCase() === 'null';

if (
  (validacao.codigo === 'CONVENIO_NAO_ACEITO' && convenioVazio) ||
  (validacao.codigo === 'MEDICO_NAO_ENCONTRADO' && medicoVazio) ||
  (validacao.codigo === 'PROCEDIMENTO_NAO_ENCONTRADO' && !parsedData.dados.atendimento_nome)
) {
  return [{
    json: {
      texto_final: parsedData.resposta_social,
      clinica_id: trigger.clinica_id,
      telefone: trigger.telefone,
      nome: trigger.nome,
      instancia: trigger.instancia
    }
  }];
}

// Fallbacks para mensagens reais de erro (dados preenchidos mas inválidos)
const medicoNome = parsedData.dados.medico_nome || "o médico informado";
const convenioNome = parsedData.dados.convenio || "o convênio mencionado";
const conveniosLista = validacao.convenios_aceitos ? validacao.convenios_aceitos.join(', ') : 'nossos convênios parceiros';

let resposta = '';

switch (validacao.codigo) {
  case 'MEDICO_NAO_ENCONTRADO':
    resposta = `O médico ${medicoNome} não atende na nossa clínica. Gostaria de saber quais médicos atendem por aqui?`;
    break;
  case 'CONVENIO_NAO_ACEITO':
    resposta = `${validacao.medico_encontrado} não atende ${convenioNome}.\n\nConvênios aceitos: ${conveniosLista}.\n\nDeseja agendar como PARTICULAR ou verificar outro médico?`;
    break;
  case 'PROCEDIMENTO_NAO_ENCONTRADO':
    resposta = `A clínica não realiza o procedimento "${parsedData.dados.atendimento_nome || 'solicitado'}". Posso ajudar com outro serviço?`;
    break;
  default:
    resposta = parsedData.resposta_social;
}

return [{
  json: {
    texto_final: resposta,
    clinica_id: trigger.clinica_id,
    telefone: trigger.telefone,
    nome: trigger.nome,
    instancia: trigger.instancia
  }
}];

const dados = $('parsearRespostaLLM').first().json;
const trigger = $('receberDadosWorkflowPai').first().json;
const intencao = (dados.intencao || '').trim().toLowerCase();
const limpar = (val) => {
  if (val === null || val === undefined) return '';
  const s = String(val).trim().toLowerCase();
  return (s === '' || s === 'null' || s === 'undefined') ? '' : s;
};
const medico = limpar(dados.dados?.medico_nome);
const convenio = limpar(dados.dados?.convenio);
const procedimento = limpar(dados.dados?.atendimento_nome);

// SÓ VALIDAMOS SE:
// Tivermos Médico E Convênio (para checar o par)
// Procedimento sozinho sem médico+convênio não tem o que validar
const temParParaValidar = (medico !== '' && convenio !== '');

const precisaValidar = intencao === 'agendar' && temParParaValidar;

return [{
  json: {
    precisaValidar,
    intencao,
    dados: dados.dados,
    resposta_social: dados.resposta_social,
    pronto_para_acao: dados.pronto_para_acao,
    clinica_id: trigger.clinica_id,
    telefone: trigger.telefone,
    nome: trigger.nome
  }
}];

