value.allowed_services_json:
={{ (() => {
  const parentValue = $('receberDadosWorkflowPai').first().json.allowed_services_json;
  if (typeof parentValue === 'string' && parentValue.trim()) return parentValue;
  const contextoRuntime = $('buscarConfigClinica').first().json.contexto_runtime || {};
  const agendamentoContext = contextoRuntime.agendamento || {};
  const candidates = [
    contextoRuntime.allowed_services,
    contextoRuntime.servicos_permitidos,
    agendamentoContext.allowed_services,
    agendamentoContext.servicos_permitidos
  ];
  const resolved = candidates.find((value) => value !== undefined && value !== null && value !== '');
  if (Array.isArray(resolved)) return JSON.stringify(resolved);
  if (typeof resolved === 'string') return resolved.trim() || '[]';
  return '[]';
})() }}
